// Obtener datos de los queries
const kpis = $('Query KPIs').first().json;
const categorias = $('Query Top Categorías').all().map(i => i.json);
const metricas = $('Query Métricas').first().json;

// Formatear top categorías
let topCats = '';
for (let i = 0; i < categorias.length; i++) {
  topCats += `   ${i+1}. ${categorias[i].categoria}: R$ ${Number(categorias[i].revenue).toLocaleString('pt-BR', {minimumFractionDigits: 2})}\n`;
}

// Construir mensaje
const mensaje = `🛒 *OLIST E-COMMERCE — REPORTE*
━━━━━━━━━━━━━━━━━━━━━━

📊 *KPIs Generales*
   Total Órdenes: ${Number(kpis.total_ordenes).toLocaleString()}
   Clientes Únicos: ${Number(kpis.total_clientes).toLocaleString()}
   Revenue Total: R$ ${Number(kpis.revenue_total).toLocaleString('pt-BR', {minimumFractionDigits: 2})}
   Ticket Promedio: R$ ${Number(kpis.ticket_promedio).toLocaleString('pt-BR', {minimumFractionDigits: 2})}

🏆 *Top 5 Categorías por Revenue*
${topCats}
📦 *Logística*
   Tiempo promedio de entrega: ${metricas.dias_entrega} días
   Entregas tardías: ${metricas.pct_entregas_tardias}%

⚠️ *Incidencias*
   Cancelaciones: ${metricas.pct_canceladas}%
   Reviews negativas (1-2): ${metricas.pct_reviews_negativas}%

━━━━━━━━━━━━━━━━━━━━━━
🤖 Generado automáticamente por el pipeline Olist`;

return [{ json: { mensaje } }];
